use std::sync::Mutex;
pub struct Counter { m: Mutex<i32> }
impl Counter {
    pub fn inc(&self) {
        let mut g = self.m.lock().unwrap();
        *g += 1;
    }
}

pub fn concat_strings(parts: &[&str]) -> String {
    let cap: usize = parts.iter().map(|s| s.len()).sum();
    let mut r = String::with_capacity(cap);
    for p in parts { r.push_str(p); }
    r
}

